#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(packet.packet_id);

    // Read username using prefixed<std::string> adaptor
    adaptor >> hexi::prefixed(packet.username);

    // Read scores vector: read the count, then use read_container with the count
    uint32_t score_count;
    adaptor.read(score_count);
    adaptor.read_container(packet.scores, score_count);

    // Read metadata string using null_terminated<std::string> adaptor
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.size());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Use span() to get a view of the first 4 bytes (packet_id)
    auto id_span = adaptor.span(4);
    info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());

    // Read username using prefixed<std::string_view> adaptor
    adaptor >> hexi::prefixed(info.username);

    // Read the count of scores, then skip the scores vector
    uint32_t score_count;
    adaptor.read(score_count);
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
