    // We need to ensure there's enough data for the header and items
    // Header: 1 byte (data_type) + 4 bytes (item_count) = 5 bytes
    if (stream.size() < 5) {
        // Not enough data for header - return empty result
        return result;
    }

    // Read the item_count using the binary_stream's get() function
    uint32_t item_count;
    stream.get(item_count);

