    uint64_t* block1 = allocator.allocate();
    std::cout << "Allocated block1 - Free list size decreased by 1" << std::endl;

    // Demonstrate deallocation (which internally calls push())
    allocator.deallocate(block1);
    std::cout << "Deallocated block1 - Free list size increased by 1" << std::endl;

    // Demonstrate multiple allocations/deallocations to show LIFO behavior
    uint64_t* block2 = allocator.allocate();
    uint64_t* block3 = allocator.allocate();

    std::cout << "\nLIFO Behavior Demonstration:" << std::endl;
    std::cout << "Allocated block2, then block3" << std::endl;

    // Deallocate in reverse order to show last-in-first-out
    allocator.deallocate(block3);
    std::cout << "Deallocated block3 - Should become head of free list" << std::endl;

    allocator.deallocate(block2);
    std::cout << "Deallocated block2 - Now free list head" << std::endl;

    // Verify the behavior by checking if we get the expected blocks back
    uint64_t* block4 = allocator.allocate();
    uint64_t* block5 = allocator.allocate();

    std::cout << "\nVerification:" << std::endl;
