#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a hexi::file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer was created successfully (no errors)
    if (!buffer || buffer.error()) {
        return {}; // Return empty vector on error
    }

    // Adjust header_size if it exceeds the available data in the file
    if (header_size > buffer.size()) {
        header_size = buffer.size();
    }

    // Create a vector to store the header data with the appropriate size
    std::vector<uint8_t> header_data(header_size);

    // Use the copy method of hexi::file_buffer to copy the header data without advancing the read pointer
    buffer.copy(header_data.data(), header_size);

    // Return the vector containing the header data
    return header_data;
}
```

## Key Implementation Points:

1. **File Buffer Creation**: Uses `hexi::file_buffer buffer(file_path)` to create the file buffer object as specified.

2. **Error Handling**: Checks both `!buffer` (operator bool) and `buffer.error()` to ensure the file was opened successfully.

3. **Size Adjustment**: Properly handles cases where `header_size` exceeds the actual file size by setting it to `buffer.size()`.

4. **Vector Allocation**: Creates a vector with the exact required size using `std::vector<uint8_t> header_data(header_size)`.

5. **Non-Advancing Copy**: Uses `buffer.copy(header_data.data(), header_size)` which, according to the reference materials, copies data without advancing the read pointer.

6. **Return Value**: Returns the populated vector containing the header data.

This implementation follows all the specified assessment objectives and correctly utilizes the `hexi::file_buffer` API as documented in the reference materials.

