#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Use the put method of binary_stream_writer to write the value as a varint
    writer.put(value);
    // Return the number of bytes written (difference in total_write before and after)
    return writer.total_write();
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    // Use the get method of binary_stream_reader to read a varint
    return reader.get<T>();
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer (std::vector<std::byte>) to hold the encoded data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor<std::vector<std::byte>> adaptor(buffer);

    // Create binary_stream_writer and binary_stream_reader using the buffer_adaptor
    hexi::pmc::binary_stream_writer writer(adaptor);
    hexi::pmc::binary_stream_reader reader(adaptor);

    // Encode the original value using the writer
    writer.put(original_value);

    // Decode the value using the reader
    T decoded_value = reader.get<T>();

    // Compare the decoded value with the original value and return the result
    return decoded_value == original_value;
}
