    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;

    // Use view to extract null-terminated sensor name string (if present)
    auto name_view = buffer.view();
    if (!name_view.empty()) {
        info.sensor_name = name_view;
    }

    // Use enforce_read_bounds to check if there's enough data before reading sensor_id
    hexi::enforce_read_bounds(buffer.size(), sizeof(uint32_t));

    // Read sensor_id directly
    info.sensor_id = *reinterpret_cast<const uint32_t*>(buffer.data());

    // Skip the remaining data using skip
    // Calculate remaining bytes: total buffer size minus what we've already read
    size_t remaining_bytes = buffer.size() - sizeof(uint32_t);
    if (remaining_bytes > 0) {
        // Create a temporary adaptor to skip remaining data
        hexi::buffer_adaptor<const std::span<const uint8_t>> temp_adaptor(buffer);
        temp_adaptor.skip(remaining_bytes);
    }

    return info;
}
